//-----------------------------------------------------------------------------
// MRFGenericProcessToolsCmdDlg : Build
//-----------------------------------------------------------------------------
void MRFGenericProcessToolsCmdDlg::Build(CATUnicodeString baseNLSName)
{
	if (_pMainFrame)
	{
		_pSelectorListFrame = new CATDlgFrame(_pMainFrame, (const char*)"MainFrame", 0 | CATDlgFraNoTitle | CATDlgFraNoFrame | CATDlgGridLayout);
		_pSelectorListFrame->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);
		
		_pLabelProcessToolType = new CATDlgLabel(_pSelectorListFrame, (const char*)"Generic Process Tool Type", 0 | CATDlgLabLeft);
		_pLabelProcessToolType->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);

		_pComboProcessToolType = new CATDlgCombo(_pSelectorListFrame, (const char*)"Combo_ProcessTool_Type", 0 | CATDlgCmbDropDown);
		_pComboProcessToolType->SetGridConstraints(0, 1, 1, 1, CATGRID_4SIDES);
		_pComboProcessToolType->SetVisibleTextWidth(20);
		_pComboProcessToolType->SetLine("Select Process Tool Type");
		this->SetComboBoxValuesReadFromNLS(_pComboProcessToolType, baseNLSName);

		_pEditModeFrame = new CATDlgFrame(_pMainFrame, (const char*)"Edit Mode", 0 | CATDlgGridLayout);
		_pEditModeFrame->SetGridConstraints(1, 0, 1, 1, CATGRID_4SIDES);


		_pRadioButtonEditMode = new CATDlgCheckButton(_pEditModeFrame, (const char*)"", 0 | CATGRID_4SIDES);
		_pRadioButtonEditMode->SetGridConstraints(0, 0,1, 1, CATGRID_4SIDES);

		_pLabelGeomSet = new CATDlgLabel(_pEditModeFrame, (const char*)"Root Geometrical Set", 0 | CATDlgLabLeft);
		_pLabelGeomSet->SetGridConstraints(1, 0, 1, 1, CATGRID_4SIDES);

		_pSelectorListGeomSet = new CATDlgSelectorList(_pEditModeFrame, (const char*)"SelectorList_GeomSet");
		_pSelectorListGeomSet->SetGridConstraints(1,1, 1, 1, CATGRID_4SIDES);
		_pSelectorListGeomSet->SetVisibleTextHeight(1);
		_pSelectorListGeomSet->SetVisibleTextWidth(20);
		_pSelectorListGeomSet->SetLine("Select Geometrical Set");
		_pSelectorListGeomSet->SetSensitivity(CATDlgDisable);
	}

}
//-----------------------------------------------------------------------------
// MRFGenericProcessToolsCmdDlg : SetComboBoxValuesReadFromNLS
// Set combo box vaues read from the NLS file
//-----------------------------------------------------------------------------
void MRFGenericProcessToolsCmdDlg::SetComboBoxValuesReadFromNLS(CATDlgCombo *pComboBox, CATUnicodeString NLSFileName)
{

	if (!pComboBox)
		return;

	CATUnicodeString  profileCountAsStr;
	int ProcessToolCount = 0;
	CATString NLSFileNameLoc = NLSFileName, udfCountName = NLSFileNameLoc + ".Count";

	profileCountAsStr = CATMsgCatalog::BuildMessage(NLSFileNameLoc, udfCountName);
	profileCountAsStr.ConvertToNum(&ProcessToolCount, "%d");

	CATUnicodeString UDFNameListLines[100], udfName;
	bool atleatOneProfileFound = false;

	int UDFFound_Count = 0;
	for (int i = 1; i <= ProcessToolCount; i++)
	{
		CATString NLSFileNameLocal = NLSFileName;

		CATString profileName = NLSFileNameLocal + ".";

		CATUnicodeString CountAsStr;
		CountAsStr.BuildFromNum(i);
		profileName.Append(CountAsStr.ConvertToChar());
		profileName.Append(".NLSConfigFileName");

		udfName = CATMsgCatalog::BuildMessage(NLSFileNameLoc, profileName);
		if (!udfName.Compare(""))
		{
			UDFNameListLines[i - 1] = udfName;
			atleatOneProfileFound = true;
			UDFFound_Count++;
		}
	}


	if (atleatOneProfileFound)
		pComboBox->SetLine(UDFNameListLines, UDFFound_Count);
	else
		MRFGenericUtils::ShowErrorMessage("No Config File found");
}
//-----------------------------------------------------------------------------
// MRFGenericProcessToolsCmdDlg : UpdateSelectorList
// Updates the selector list with the name of the object
//-----------------------------------------------------------------------------
void MRFGenericProcessToolsCmdDlg::UpdateSelectorList(CATUnicodeString aliasNameToSet)
{
	CATDlgSelectorList *pSelectorList_actual = _pSelectorListGeomSet;

	if (pSelectorList_actual)
	{
		pSelectorList_actual->ClearLine();
		pSelectorList_actual->SetLine(aliasNameToSet);

		int select = 0;
		pSelectorList_actual->SetSelect(&select, 1, 0);
	}
}
